    # If either dictionary is empty, return None
    if not d1 or not d2:
        return None

    # Initialize a result list with all keys from the first dictionary
    res = [k for k in d1.keys()]

    # Iterate over the second dictionary and update the result list
    for key in d2:
        if key in res:
            continue  # Skip already processed keys
